// frontend/src/pages/ProfilePage.js
import { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const ProfilePage = () => {
  const { user, setUser } = useAuth();

  const [name, setName] = useState(user?.name || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [pic, setPic] = useState(null);
  const [curPw, setCurPw] = useState('');
  const [newPw, setNewPw] = useState('');
  const [msg, setMsg] = useState('');

  const handleProfile = async (e) => {
    e.preventDefault();
    setMsg('');

    const fd = new FormData();
    fd.append('name', name);
    fd.append('bio', bio);
    if (pic) fd.append('profilePic', pic);

    try {
      const { data } = await API.put('/auth/profile', fd);
      setUser(data);
      setMsg('Profile updated successfully!');
    } catch (err) {
      setMsg(err.response?.data?.message || 'Error updating profile');
    }
  };

  const handlePassword = async (e) => {
    e.preventDefault();
    setMsg('');
    try {
      await API.put('/auth/change-password', {
        currentPassword: curPw,
        newPassword: newPw,
      });
      setMsg('Password changed successfully!');
      setCurPw('');
      setNewPw('');
    } catch (err) {
      setMsg(err.response?.data?.message || 'Error changing password');
    }
  };

  const picSrc = user?.profilePic
    ? `http://localhost:5000/uploads/${user.profilePic}`
    : '/default-avatar.png';

  
    const styles = {
  page: {
    backgroundColor: '#FAE8ED',
    minHeight: '100vh',
    padding: '40px 20px',
    fontFamily: 'Georgia, serif',
    color: 'rgb(12, 75, 52)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
  },

  container: {
    width: '100%',
    maxWidth: '650px',
    backgroundColor: '#f7c6d9',
    padding: '35px',
    borderRadius: '25px',
    boxShadow: '0 12px 35px rgba(0,0,0,0.12)',
    textAlign: 'center',
  },

  heading: {
    fontSize: '34px',
    marginBottom: '20px',
    fontWeight: 'bold',
  },

  profilePic: {
    width: '130px',
    height: '130px',
    borderRadius: '50%',
    objectFit: 'cover',
    marginBottom: '20px',
    border: '5px solid #fff',
    boxShadow: '0 6px 18px rgba(0,0,0,0.15)',
  },

  message: {
    marginBottom: '15px',
    fontWeight: 'bold',
    color: '#ff4d4d',
  },

  form: {
    display: 'flex',
    flexDirection: 'column',
    gap: '15px',
    marginTop: '20px',
    marginBottom: '30px',
    textAlign: 'left',
  },

  subHeading: {
    marginTop: '10px',
    marginBottom: '8px',
    fontSize: '20px',
    fontWeight: 'bold',
    textAlign: 'center',
  },

  input: {
    padding: '14px 20px',
    borderRadius: '50px',
    border: '2px solid transparent',
    outline: 'none',
    backgroundColor: '#fff',
    fontFamily: 'Georgia, serif',
    fontSize: '15px',
    transition: '0.3s ease',
  },

  inputFocus: {
    borderColor: 'rgb(12, 75, 52)',
    boxShadow: '0 6px 15px rgba(12, 75, 52, 0.15)',
  },

  textarea: {
    padding: '14px 20px',
    borderRadius: '15px',
    border: '2px solid transparent',
    outline: 'none',
    backgroundColor: '#fff',
    fontFamily: 'Georgia, serif',
    fontSize: '15px',
    resize: 'none',
    transition: '0.3s ease',
  },

  fileInput: {
    marginTop: '5px',
    fontSize: '14px',
  },

  button: {
    padding: '14px',
    borderRadius: '50px',
    border: 'none',
    fontWeight: 'bold',
    cursor: 'pointer',
    backgroundColor: 'rgb(12, 75, 52)',
    color: '#f7c6d9',
    transition: 'all 0.3s ease',
    boxShadow: '0 5px 15px rgba(12, 75, 52, 0.2)',
  },

  buttonHover: {
    backgroundColor: 'rgb(241, 125, 194)',
    color: '#fff',
    transform: 'scale(1.05)',
  },

  buttonActive: {
    transform: 'scale(0.97)',
  },
};

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>My Profile</h2>

        <img src={picSrc} alt='Profile' style={styles.profilePic} />

        {msg && <p style={styles.message}>{msg}</p>}

        {/* Edit Profile */}
        <form style={styles.form} onSubmit={handleProfile}>
          <h3 style={styles.subHeading}>Edit Profile</h3>

          <input
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder='Display name'
            style={styles.input}
          />

          <textarea
            value={bio}
            onChange={(e) => setBio(e.target.value)}
            placeholder='Short bio...'
            rows={3}
            style={styles.textarea}
          />

          <label>Change Profile Picture:</label>
          <input
            type='file'
            accept='image/*'
            onChange={(e) => setPic(e.target.files[0])}
            style={styles.fileInput}
          />

          <button type='submit' style={styles.button}>
            Save Profile
          </button>
        </form>

        {/* Change Password */}
        <form style={styles.form} onSubmit={handlePassword}>
          <h3 style={styles.subHeading}>Change Password</h3>

          <input
            type='password'
            placeholder='Current password'
            value={curPw}
            onChange={(e) => setCurPw(e.target.value)}
            required
            style={styles.input}
          />

          <input
            type='password'
            placeholder='New password (min 6 chars)'
            value={newPw}
            onChange={(e) => setNewPw(e.target.value)}
            required
            minLength={6}
            style={styles.input}
          />

          <button type='submit' style={styles.button}>
            Change Password
          </button>
        </form>
      </div>
    </div>
  );
};

export default ProfilePage;
